select

from sys_user a left join sys_dept c on a.deptid = c.id left join biz_wx_user b on a.phone = b.phone left join biz_yck_balance d on b.openid = d.openid
where status != 3

	and (a.phone like CONCAT('%',#{user.name},'%')
	or a.account like CONCAT('%',#{user.name},'%')
	or a.name like CONCAT('%',#{user.name},'%'))


	and a.province = #{user.province}


	and a.city = #{user.city}


	and a.area = #{user.area}


	and a.account = #{user.account}

select

from sys_user a left join sys_dept c on a.deptid = c.id left join biz_wx_user b on a.phone = b.phone
where status != 3

	and (a.phone like CONCAT('%',#{user.name},'%')
	or account like CONCAT('%',#{user.name},'%')
	or name like CONCAT('%',#{user.name},'%'))


	and province = #{user.province}


	and city = #{user.city}


	and area = #{user.area}
